VALUES
  ('heelevel3-5ff21eeb-moex-00004', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-4bf6d96a', 'sub-heelevel3-5ff21eeb-01', NULL, 'essay', '甲主張其對乙及丙分別有新臺幣（下同）100萬元及 80 萬元之債權，並
向法院聲請對乙及丙核發支付命令。法院裁定准許甲對乙、甲對丙之支
付命令聲請，乙於收到支付命令後第五天對該支付命令提出異議，丙則
於收到支付命令後第二十五天對該支付命令提出異議。試問：上述兩個
支付命令經乙與丙分別異議後所生之法律效力為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "27192852503f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0910", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00005', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'essay', '甲將其所有之 A屋出租予乙經營托嬰中心，租期五年。詎料在租賃存續
期間，乙僱用之托育人員丙過失疏於照顧入睡中之嬰兒丁，造成丁於 A
屋窒息死亡，致甲所有之 A屋價值減損新臺幣（下同）300萬元。試問：
甲依民法第 432條、第 433條請求乙賠償該 300萬元之損害，是否有理
由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00006', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'essay', '甲有名牌女鑽錶 A 一只，甲於民國（下同）113 年 12 月 31 日參加跨年
晚會時，不慎遺失 A 錶，當晚為乙所拾獲。乙為取悅其女友丙，114 年
3 月 1 日於丙生日之際，將 A錶贈與並交付給善意且無重大過失不知之
丙。同年 6 月 1日甲向丙請求返還 A鑽錶，丙則以善意且無重大過失不
知為由，拒絕返還。試問：
乙、丙贈與契約之效力如何？（10分）
甲以所有物返還請求權向丙主張返還 A錶，是否有理由？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00007', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲與乙為同一棟社區之住戶，甲住8樓，乙住7樓，甲生性愛熱鬧，常常邀約親朋好友到家作客， 並大聲喧嘩，甚至已半夜時分仍在家中高歌作樂。下列敘述，何者錯誤？', '["在他人居住區域，發出超越一般人社會生活所能忍受之噪音，屬不法侵害他人居住安寧之人格 利益", "人格利益至高無上，不容侵犯，只要遭受侵害，不問程度如何，被害人均得依民法第195條第 1項有關人格及身分法益侵害規定，請求賠償相當之金額", "如果長期、持續性噪音，已使人因此無法入眠，健康受損，可能構成健康權之侵害", "健康權屬於特別人格權，若受侵害，被害人得請求非財產上之金錢賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00008', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲將A地出賣於乙，並辦理所有權移轉登記。下列關於所有權移轉之敘述，何者錯誤？', '["應以書面為之", "非經登記，不生效力", "非經移轉占有，不生效力", "此移轉行為係法律行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00009', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '父親甲贈與未成年子女乙一棟房屋，由甲代理乙受領，其效力如何？', '["無效", "有效", "效力未定", "得撤銷 22420"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00010', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '民法中關於權利主體「自然人」之規定，下列敘述，何者正確？', '["某藝人以「小香瓜」為藝名，因其非真名，不受民法有關姓名權規定之保護", "甲與乙同時遇難，不能證明死亡先後時，視為同時死亡", "丙因失蹤多時生死不明，被妻子依法聲請法院宣告其死亡。但丙實則仍生存中，卻因已受死亡 宣告，所以權利能力及行為能力均為消滅", "丁開車闖紅燈撞上正在過馬路之孕婦戊，致其胎兒受傷。戊為胎兒之法定代理人，固得代為受 領丁給付之賠償金，但若嗣後胎兒死產，該受領之賠償金應返還丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00011', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲依民法規定發起設立A學術性社團法人，並將其主事務所設於臺中市。依民法規定，A法人應 向何主管機關登記，始得成立？', '["臺中市政府", "臺中地方法院", "內政部", "教育部"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00012', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '甲80歲，罹輕度失智症，配偶已歿，有子女乙、丙、丁，平日由女兒乙照顧，乙擔心甲因心智缺 陷，而面臨不必要之法律糾紛，遂向法院聲請為甲為輔助宣告，法院經審查對甲為輔助宣告，並 以乙為甲之輔助人。下列甲之行為，何者須先取得輔助人乙之同意？', '["甲與好友相約到餐廳吃飯", "甲在好友A、B偕同下到C公證人處，在A、B、C見證下自書遺囑，就其法定繼承人乙、丙、 丁為遺產分配各得1/2、1/4、1/4", "甲因開車造成D受傷，自行與D成立和解契約，願意理賠D之身體傷害新臺幣（下同）50萬元", "甲自行到某百貨公司購買價錢1萬元之手錶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00013', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9b7ab1bb', 'sub-heelevel3-5ff21eeb-02', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者錯誤？', '["債務人或第三人提供其不動產為擔保", "得擔保不確定或概括債權，例如約定擔保債權人與債務人間「現在及將來一切債務及其利息、 遲延利息、違約金、實行抵押權費用」", "得擔保一定範圍內之不特定債權", "所擔保之債權，應受最高額度限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
